import configparser
import os

class ConfigParserWithComments(configparser.ConfigParser):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self._comments = {}

    def set_comment(self, section, comment):
        if section not in self._comments:
            self._comments[section] = []
        self._comments[section].append(comment)

    def write(self, fp):
        for section in self.sections():
            fp.write(f'[{section}]\n')
            if section in self._comments:
                for comment in self._comments[section]:
                    fp.write(f'# {comment}\n')
            for key, value in self[section].items():
                fp.write(f'{key} = {value}\n')
            fp.write('\n')

def serialize(config, path):
    with open(path, 'w') as file:
        config.write(file)

def main():
    config = ConfigParserWithComments()
    config['General'] = {'version': '1.0', 'enabled': 'yes'}
    config['User'] = {'name': 'Alice "A"', 'email': 'alice@example.com;key=value'}
    config.set_comment('General', 'This is a comment for General section')
    config.set_comment('User', 'User comments')
    path = 'test_config.ini'
    serialize(config, path)
    if os.path.exists(path):
        with open(path, 'r') as f:
            content = f.read()
        print('Configuration file content:')
        print(content)
    else:
        print('Failed to create configuration file.')

if __name__ == '__main__':
    main()
